using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 renames the discriminator property
            // from "Discriminator" to "$type". Existing 500K documents use
            // "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name so existing documents remain readable.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF Core 9 changes the id format from
            // "EntityType|Key" (e.g. "Product|123") to just the key value ("123").
            // Existing documents use the old format. Preserve it so lookups work.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });

        // BREAKING CHANGE 3: HasIndex() now throws on the Cosmos provider
        // because Cosmos DB doesn't support client-defined indexes.
        // Removed: entity.HasIndex(p => p.Sku);
        // If you need an index, define it via Cosmos indexing policy in the Azure portal.
    }
}
